import{_ as e,o as a,c as l,a7 as s}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"意識潜游（Consciousness Dive）","description":"","frontmatter":{},"headers":[],"relativePath":"ja/modes/consciousness-dive.md","filePath":"ja/modes/consciousness-dive.md","lastUpdated":1775394001000}'),i={name:"ja/modes/consciousness-dive.md"};function n(o,t,d,r,c,h){return a(),l("div",null,[...t[0]||(t[0]=[s('<h1 id="意識潜游-consciousness-dive" tabindex="-1">意識潜游（Consciousness Dive） <a class="header-anchor" href="#意識潜游-consciousness-dive" aria-label="Permalink to &quot;意識潜游（Consciousness Dive）&quot;">​</a></h1><p><strong>意識潜游</strong>は高難度のチャレンジコンテンツです。覚醒体の意識の深層へ潜り、次々と現れる強敵を撃破していきます。</p><h2 id="基本ルール" tabindex="-1">基本ルール <a class="header-anchor" href="#基本ルール" aria-label="Permalink to &quot;基本ルール&quot;">​</a></h2><ul><li>階層制の高難度コンテンツ</li><li>階層が進むごとに敵の強さが上昇</li><li>到達階層に応じて報酬を獲得</li><li>毎シーズンで進行がリセットされる</li></ul><h2 id="階層構成" tabindex="-1">階層構成 <a class="header-anchor" href="#階層構成" aria-label="Permalink to &quot;階層構成&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">階層</th><th style="text-align:left;">難易度</th><th style="text-align:left;">特徴</th></tr></thead><tbody><tr><td style="text-align:center;">1〜10層</td><td style="text-align:left;">初級</td><td style="text-align:left;">チュートリアル相当。育成済み覚醒体で容易にクリア</td></tr><tr><td style="text-align:center;">11〜20層</td><td style="text-align:left;">中級</td><td style="text-align:left;">編成の工夫が必要に</td></tr><tr><td style="text-align:center;">21〜30層</td><td style="text-align:left;">上級</td><td style="text-align:left;">装備・刻印の厳選が求められる</td></tr><tr><td style="text-align:center;">31層〜</td><td style="text-align:left;">超級</td><td style="text-align:left;">最適編成・最高戦力が必要</td></tr></tbody></table><h2 id="報酬" tabindex="-1">報酬 <a class="header-anchor" href="#報酬" aria-label="Permalink to &quot;報酬&quot;">​</a></h2><p><em>準備中...</em></p><h2 id="攻略のコツ" tabindex="-1">攻略のコツ <a class="header-anchor" href="#攻略のコツ" aria-label="Permalink to &quot;攻略のコツ&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>意識潜游では各階層にギミックが存在します。ギミックに合わせて編成を変更することが攻略の鍵です。</p></div><p><em>準備中...</em></p><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./combat.html">戦闘システム</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li><li><a href="./">ゲームモード一覧</a></li></ul>',13)])])}const f=e(i,[["render",n]]);export{m as __pageData,f as default};
